import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function extractAlphaSignals(chainName, watchlist) {
  const signals = await Promise.all(
    watchlist.map(wallet =>
      client.TransactionService.getTransactionsForAddressV3(chainName, wallet, { pageSize: 10 })
    )
  );
  return signals.flatMap((s, i) =>
    (s.data?.items ?? []).map(tx => ({ wallet: watchlist[i], tx }))
  );
}
